const data = $input.first().json;
return data.candidates.map(function(email) {
  return { json: { email_address: email, domain: data.domain } };
});

const domain = $('Extract Input').first().json.domain;
const candidates = $('Extract Input').first().json.candidates || [];
return [{ json: { candidates, domain, probe_start: new Date().toISOString() } }];

// Input 0 (from Wait): { candidates, domain, probe_start }
// Input 1 (from Query Bounces): 0..N items with { bounced_email } — may be 0 items
const allItems = $input.all().map(function(i) { return i.json; });

// Bounce rows have a bounced_email field
const bouncedSet = new Set(
  allItems
    .filter(function(r) { return r.bounced_email; })
    .map(function(r) { return r.bounced_email.toLowerCase(); })
);

// Candidates/domain come from Aggregate After Send (guaranteed present)
const candidates = $('Aggregate After Send').first().json.candidates || [];
const domain = $('Aggregate After Send').first().json.domain;

const results = candidates.map(function(email) {
  return {
    email: email,
    status:      bouncedSet.has(email.toLowerCase()) ? 'invalid'      : 'likely_valid',
    confidence:  bouncedSet.has(email.toLowerCase()) ? 'high'         : 'medium',
    smtp_result: bouncedSet.has(email.toLowerCase()) ? 'bounced'      : 'no_bounce',
    method: 'probe'
  };
});

results.sort(function(a, b) { return a.status === 'likely_valid' ? -1 : 1; });

const probe_start = $('Aggregate After Send').first().json.probe_start;
return [{ json: { candidates: results, domain: domain, total: results.length, method: 'probe', probe_start } }];
